import{_ as a,c as o,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Apéndice: Guía de Referencia | oh-my-opcode","description":"Domina las opciones de configuración de oh-my-opencode, la compatibilidad con Claude Code y los servidores MCP integrados. Esta referencia cubre los pasos de migración y las capacidades de búsqueda para personalizar tu entorno OpenCode y extender los flujos de trabajo de IA.","frontmatter":{"title":"Apéndice: Guía de Referencia | oh-my-opcode","sidebarTitle":"Apéndice","subtitle":"Apéndice: Guía de Referencia y Compatibilidad","description":"Domina las opciones de configuración de oh-my-opencode, la compatibilidad con Claude Code y los servidores MCP integrados. Esta referencia cubre los pasos de migración y las capacidades de búsqueda para personalizar tu entorno OpenCode y extender los flujos de trabajo de IA.","tags":["Apéndice","Referencia"],"order":170},"headers":[],"relativePath":"es/code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"es/code-yeongyu/oh-my-opencode/appendix/index.md"}'),n={name:"es/code-yeongyu/oh-my-opencode/appendix/index.md"};function d(t,e,s,c,l,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="apendice-guia-de-referencia-y-compatibilidad" tabindex="-1">Apéndice: Guía de Referencia y Compatibilidad <a class="header-anchor" href="#apendice-guia-de-referencia-y-compatibilidad" aria-label="Permalink to &quot;Apéndice: Guía de Referencia y Compatibilidad&quot;">​</a></h1><p>Este capítulo contiene materiales de referencia detallados y directrices de compatibilidad para <strong>oh-my-opencode</strong>, que cubre la documentación completa de configuración, el soporte de migración de Claude Code y presentaciones detalladas de los servidores de extensión integrados.</p><h2 id="contenido-del-capitulo" tabindex="-1">Contenido del Capítulo <a class="header-anchor" href="#contenido-del-capitulo" aria-label="Permalink to &quot;Contenido del Capítulo&quot;">​</a></h2><p>Este capítulo incluye tres secciones importantes:</p><table tabindex="0"><thead><tr><th>Subpágina</th><th>Descripción</th><th>Dificultad</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Compatibilidad con Claude Code</a></td><td>Guía completa para migrar desde Claude Code a OpenCode, incluyendo mecanismos de compatibilidad para Comandos, Habilidades, Agentes, MCPs y Hooks</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">Referencia de Configuración</a></td><td>Documentación completa del esquema para los archivos de configuración de oh-my-opencode, que cubre todos los campos, tipos y valores predeterminados</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">MCPs Integrados</a></td><td>Características y uso de 3 servidores MCP integrados (Exa Websearch, Context7, Grep.app)</td><td>⭐⭐</td></tr></tbody></table><h2 id="rutas-de-aprendizaje-recomendadas" tabindex="-1">Rutas de Aprendizaje Recomendadas <a class="header-anchor" href="#rutas-de-aprendizaje-recomendadas" aria-label="Permalink to &quot;Rutas de Aprendizaje Recomendadas&quot;">​</a></h2><p>Elige tu orden de aprendizaje según tus necesidades:</p><h3 id="ruta-1-migracion-desde-claude-code" tabindex="-1">Ruta 1: Migración desde Claude Code <a class="header-anchor" href="#ruta-1-migracion-desde-claude-code" aria-label="Permalink to &quot;Ruta 1: Migración desde Claude Code&quot;">​</a></h3><p>Si eres un usuario que migra desde Claude Code:</p><ol><li>Primero lee <strong><a href="./claude-code-compatibility/">Compatibilidad con Claude Code</a></strong> para entender cómo migrar sin problemas tu configuración existente</li><li>Luego revisa <strong><a href="./configuration-reference/">Referencia de Configuración</a></strong> para obtener una comprensión más profunda de las opciones de configuración disponibles</li><li>Finalmente aprende sobre <strong><a href="./builtin-mcps/">MCPs Integrados</a></strong> para entender cómo configurar capacidades de búsqueda adicionales</li></ol><h3 id="ruta-2-personalizacion-profunda" tabindex="-1">Ruta 2: Personalización Profunda <a class="header-anchor" href="#ruta-2-personalizacion-profunda" aria-label="Permalink to &quot;Ruta 2: Personalización Profunda&quot;">​</a></h3><p>Si deseas personalizar profundamente el comportamiento de oh-my-opencode:</p><ol><li>Comienza con <strong><a href="./configuration-reference/">Referencia de Configuración</a></strong> para entender todos los elementos configurables</li><li>Aprende sobre <strong><a href="./builtin-mcps/">MCPs Integrados</a></strong> para configurar capacidades de búsqueda y consulta de documentación</li><li>Consulta <strong><a href="./claude-code-compatibility/">Compatibilidad con Claude Code</a></strong> para entender las opciones de configuración de la capa de compatibilidad</li></ol><h3 id="ruta-3-referencia-rapida" tabindex="-1">Ruta 3: Referencia Rápida <a class="header-anchor" href="#ruta-3-referencia-rapida" aria-label="Permalink to &quot;Ruta 3: Referencia Rápida&quot;">​</a></h3><p>Si solo necesitas buscar información específica:</p><ul><li><strong>Preguntas de configuración</strong> → Ve directamente a <strong><a href="./configuration-reference/">Referencia de Configuración</a></strong></li><li><strong>Preguntas de migración</strong> → Ve directamente a <strong><a href="./claude-code-compatibility/">Compatibilidad con Claude Code</a></strong></li><li><strong>Configuración de MCP</strong> → Ve directamente a <strong><a href="./builtin-mcps/">MCPs Integrados</a></strong></li></ul><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><p>Para este capítulo, se recomienda que ya hayas:</p><ul><li>✅ Completado <strong><a href="./../start/installation/">Instalación y Configuración</a></strong></li><li>✅ Entendido los conceptos básicos de <strong><a href="./../start/sisyphus-orchestrator/">Orquestador Sisyphus</a></strong></li><li>✅ Familiaridad con la edición de archivos de configuración JSON</li></ul><h2 id="pasos-siguientes" tabindex="-1">Pasos Siguientes <a class="header-anchor" href="#pasos-siguientes" aria-label="Permalink to &quot;Pasos Siguientes&quot;">​</a></h2><p>Después de completar este capítulo, puedes:</p><ul><li>🚀 Probar <strong><a href="./../advanced/">Características Avanzadas</a></strong> para aprender un uso más avanzado</li><li>🔧 Consultar <strong><a href="./../faq/">Preguntas Frecuentes</a></strong> para resolver problemas de uso</li><li>📖 Leer <strong><a href="./../changelog/">Registro de Cambios</a></strong> para mantenerte actualizado sobre las mejoras de nuevas características</li></ul><div class="tip custom-block"><p class="custom-block-title">Consejo</p><p>El contenido de este capítulo sirve principalmente como material de referencia y no necesita leerse secuencialmente. Puedes consultar las secciones relevantes según sea necesario.</p></div>',23)])])}const g=a(n,[["render",d]]);export{m as __pageData,g as default};
